/* Default idle_player_state row shape, matching BKMP_IDLE_PLAYER_STATE_COLUMNS
   in idledorf.js (~line 2955). Teststand fixtures override only the fields
   that make that Teststand distinct; every other column gets a safe,
   internally-consistent default so nothing reads `undefined`/NaN. */

function makePlayerStateRow(authUserId, nameKey, nowIso, overrides) {
  const base = {
    auth_user_id: authUserId,
    name_key: nameKey,
    display_name: overrides.display_name || nameKey,
    level: 1,
    xp: 0,
    gold: 0,
    wood: 0,
    stone: 0,
    crystals: 0,
    essence: 0,
    total_gold_earned: 0,
    attack: 10,
    defense: 2,
    hp: 100,
    crit_chance: 5,
    crit_damage: 150,
    gold_bonus: 0,
    xp_bonus: 0,
    loot_bonus: 0,
    skill_points_available: 0,
    skill_points_spent: 0,
    skill_allocations: {},
    upgrade_purchases: {},
    dragon_kills: 0,
    boss_kills: 0,
    current_dragon_index: 0,
    highest_dragon_index: 0,
    prestige_stage_offset: 0,
    auto_advance: true,
    playtime_seconds: 0,
    last_seen_at: nowIso,
    last_offline_claim: null,
    last_skilltree_reset_at: null,
    updated_at: nowIso,
    rune_fuse_successes: 0,
    rune_fuse_failures: 0,
    rune_upgrade_successes: 0,
    rune_upgrade_failures: 0,
    village_defeats: 0,
    yaksha_boss_kills: 0,
    active_village_skin: null,
    fruit: 0,
    meat: 0,
    obstgarten_level: 0,
    jagdhuette_level: 0,
    fruit_collected_at: nowIso,
    meat_collected_at: nowIso,
    boost_gold_until: null,
    boost_exp_until: null,
    mana: 0,
    holzfaeller_level: 0,
    holzfaeller_collected_at: nowIso,
    steinbruch_level: 0,
    steinbruch_collected_at: nowIso,
    goldmine_level: 0,
    goldmine_collected_at: nowIso,
    kristallmine_level: 0,
    kristallmine_collected_at: nowIso,
    manaquelle_level: 0,
    manaquelle_collected_at: nowIso,
    magierakademie_level: 0,
    magierakademie_collected_at: nowIso,
    titles_unlocked_at: {},
    cosmetics_unlocked_at: {},
    turm_highest_wave: 0,
    turm_last_attempt_at: null,
    dragon_species_discovered_at: {}
  };
  return { ...base, ...overrides };
}

module.exports = { makePlayerStateRow };
